    // Define the order of business lines
    std::vector<std::string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Filter valid coupons
    std::vector<std::string> validCodes;
    for (size_t i = 0; i < code.size(); ++i) {
        // Check if code is not empty and only contains allowed characters
        bool isValidCode = !code[i].empty() && code[i].find_first_not_of("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_") == std::string::npos;

